// bundle-mobility.cjs — bundles Mobility IIFE modules into heys_mobility_bundle_v1.js.
//
// Run from apps/web:
//   node scripts/bundle-mobility.cjs
//   pnpm bundle:mobility
//
// Output: apps/web/heys_mobility_bundle_v1.js (auto-generated, do not edit manually).

const fs = require('fs');
const path = require('path');

const ROOT = process.cwd();
const SRC_DIR = path.join(ROOT, 'mobility');
const KERNEL_DIR = path.join(ROOT, '_kernel');
const OUT_FILE = path.join(ROOT, 'heys_mobility_bundle_v1.js');

const MODULES = [
  { file: 'heys_training_focus_ui_v1.js', label: 'shared training focus UI primitives', dir: KERNEL_DIR },
  { file: 'heys_kernel_bibliography_v1.js', label: 'shared bibliography registry (kernel)', dir: KERNEL_DIR },
  { file: 'heys_kernel_bibliography_ui_v1.js', label: 'shared bibliography UI: badge+modal (kernel)', dir: KERNEL_DIR },
  { file: 'heys_kernel_stats_v1.js', label: 'shared robust stats: median/MAD/z (kernel)', dir: KERNEL_DIR },
  { file: 'heys_kernel_dates_v1.js', label: 'shared date keys + day arithmetic (kernel)', dir: KERNEL_DIR },
  { file: 'heys_kernel_calendar_v1.js', label: 'shared calendar/grid primitives (kernel)', dir: KERNEL_DIR },
  { file: 'heys_kernel_periodization_v1.js', label: 'shared periodization phase machine (kernel)', dir: KERNEL_DIR },
  { file: 'heys_kernel_progression_v1.js', label: 'shared progression primitives (kernel)', dir: KERNEL_DIR },
  { file: 'heys_kernel_session_v1.js', label: 'shared session builder primitives (kernel)', dir: KERNEL_DIR },
  { file: 'heys_kernel_runner_v1.js', label: 'shared runner lifecycle primitives (kernel)', dir: KERNEL_DIR },
  { file: 'heys_kernel_timer_v1.js', label: 'shared timer-core: tick/pause/resume/wakeLock/owner-lock (kernel)', dir: KERNEL_DIR },
  { file: 'heys_kernel_active_session_v1.js', label: 'shared active-session snapshot persistence (kernel)', dir: KERNEL_DIR },
  { file: 'heys_kernel_router_v1.js', label: 'shared strangler router primitives (kernel)', dir: KERNEL_DIR },
  { file: 'heys_kernel_catalog_v1.js', label: 'shared catalog index: id+groupBy (kernel)', dir: KERNEL_DIR },
  { file: 'heys_kernel_assess_v1.js', label: 'shared assess math: deficit/normalize (kernel)', dir: KERNEL_DIR },
  { file: 'heys_kernel_gate_v1.js', label: 'shared validator gate: Issue+S1 level/age (kernel)', dir: KERNEL_DIR },
  { file: 'heys_kernel_records_v1.js', label: 'shared records storage: client key + JSON (kernel)', dir: KERNEL_DIR },
  { file: 'heys_kernel_onboarding_v1.js', label: 'shared onboarding/profile primitives (kernel)', dir: KERNEL_DIR },
  { file: 'heys_kernel_sports_v1.js', label: 'shared SPORT_CONFIG registry (kernel)', dir: KERNEL_DIR },
  { file: 'heys_mobility_axis_catalog_v1.js', label: 'axis catalog + enums' },
  { file: 'heys_mobility_sport_config_v1.js', label: 'SPORT_CONFIG instance' },
  { file: 'heys_mobility_bibliography_v1.js', label: 'sources + effect map (kernel registry)' },
  { file: 'heys_mobility_atom_catalog_v1.js', label: 'atom catalog A-J' },
  { file: 'heys_mobility_validators_v1.js', label: 'safety validators S1-S9' },
  { file: 'heys_mobility_assessment_v1.js', label: 'ROM assessment + limiter audit' },
  { file: 'heys_mobility_onboarding_v1.js', label: 'profile onboarding' },
  { file: 'heys_mobility_readiness_v1.js', label: 'readiness advisory' },
  { file: 'heys_mobility_records_store_v1.js', label: 'client-scoped records' },
  { file: 'heys_mobility_progression_v1.js', label: 'progression policy' },
  { file: 'heys_mobility_mode_engine_v1.js', label: 'mode engine' },
  { file: 'heys_mobility_protocols_catalog_v1.js', label: 'ready-to-run protocol catalog' },
  { file: 'heys_mobility_calendar_v1.js', label: 'weekly calendar planner' },
  { file: 'heys_mobility_routine_builder_v1.js', label: 'hybrid routine builder' },
  { file: 'heys_mobility_breath_runner_v1.js', label: 'breath runner' },
  { file: 'heys_mobility_routine_runner_v1.js', label: 'routine runner' },
  { file: 'heys_mobility_session_persistence_v1.js', label: 'active-session persistence wrapper' },
  { file: 'heys_mobility_ui_v1.js', label: 'React UI source' },
  { file: 'heys_mobility_entry_v1.js', label: 'public API' }
];

const banner = [
  '// heys_mobility_bundle_v1.js — bundled Mobility module.',
  '// Auto-generated by apps/web/scripts/bundle-mobility.cjs. Do not edit manually.',
  '// Source files: apps/web/mobility/heys_mobility_*_v1.js (' + MODULES.length + ' modules).',
  '// Order is dependency-driven — see bundle-mobility.cjs MODULES list for layers.',
  ''
].join('\n');

const chunks = [banner];
const missing = [];

for (const mod of MODULES) {
  const srcPath = path.join(mod.dir || SRC_DIR, mod.file);
  if (!fs.existsSync(srcPath)) {
    missing.push(mod.file);
    continue;
  }
  const raw = fs.readFileSync(srcPath, 'utf8').trimEnd();
  const safe = raw.startsWith(';') ? raw : ';' + raw;
  chunks.push('// ===== Begin ' + mod.file + ' — ' + mod.label + ' =====');
  chunks.push(safe);
  chunks.push('// ===== End ' + mod.file + ' =====');
  chunks.push('');
}

if (missing.length) {
  console.error('[bundle-mobility] Missing source files:');
  for (const f of missing) console.error('  - apps/web/mobility/' + f);
  process.exit(1);
}

fs.writeFileSync(OUT_FILE, chunks.join('\n'), 'utf8');

const sizeKB = (fs.statSync(OUT_FILE).size / 1024).toFixed(1);
console.info('[bundle-mobility] ' + MODULES.length + ' modules -> heys_mobility_bundle_v1.js (' + sizeKB + ' KB)');
